    {
        // Arrange & Act
        var result = new RefundResult("rf_123", true);

        // Assert
        Assert.AreEqual("rf_123", result.RefundId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void RefundResult_FailedRefund_SetsSuccessToFalse()
    {
        // Arrange & Act
        var result = new RefundResult("rf_456", false);

        // Assert
        Assert.AreEqual("rf_456", result.RefundId);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public void RefundResult_EqualityCheck_EqualRecordsAreEqual()
    {
        // Arrange
        var result1 = new RefundResult("rf_same", true);
        var result2 = new RefundResult("rf_same", true);

        // Assert
        Assert.AreEqual(result1, result2);
    }

    [TestMethod]
    public void RefundResult_EqualityCheck_DifferentRecordsAreNotEqual()
    {
        // Arrange
        var result1 = new RefundResult("rf_one", true);
        var result2 = new RefundResult("rf_two", false);

        // Assert
        Assert.AreNotEqual(result1, result2);
    }

