    // PaymentGateway instantiation
    // ──────────────────────────────────────────────

    [TestMethod]
    public void PaymentGateway_CanBeInstantiated()
    {
        // Act
        var gateway = new Payments.PaymentGateway();

        // Assert
        Assert.IsNotNull(gateway);
    }
}

